findings.fix:
Track a Map<original, scrubbed> rather than a WeakSet<original> so cycle back-references can return the already-being-built scrubbed output:

export function scrubSecrets(input: unknown): unknown {
  const seen = new Map<object, unknown>();
  function walk(v: unknown): unknown {
    if (typeof v === 'string') return scrubString(v);
    if (v === null || typeof v !== 'object') return v;
    if (OpaqueRelayerKey.is(v)) return REDACTED;
    if (seen.has(v)) return seen.get(v); // return partial scrubbed copy
    if (Array.isArray(v)) {
      const out: unknown[] = [];
      seen.set(v, out);
      for (const item of v) out.push(walk(item));
      return out;
    }
    const out: Record<string, unknown> = {};
    seen.set(v, out); // register before recursing
    for (const [k, val] of Object.entries(v)) {
      out[k] = walk(val);
    }
    return out;
  }
  return walk(input);
}

The test should also be strengthened to assert out.self.v === REDACTED.
